// File: http_demo.dart
// Run: dart http_demo.dart
import 'dart:convert';
import 'package:http/http.dart' as http;

void main() async {
  final url = Uri.parse('https://httpbin.org/get?hello=world');

  print('--- Request ---');
  print('GET  ${url}');
  print('Headers: User-Agent: dart-demo, Accept: application/json');

  final t0 = DateTime.now();
  final res = await http.get(url, headers: {
    'User-Agent': 'dart-demo',
    'Accept':     'application/json',
  });
  final ms = DateTime.now().difference(t0).inMilliseconds;

  print('\n--- Response ($ms ms) ---');
  print('Status: ${res.statusCode} ${res.reasonPhrase}');
  print('Headers:');
  res.headers.forEach((k, v) => print('  $k: $v'));

  print('\n--- Body (first 200 chars) ---');
  print(res.body.substring(0, res.body.length.clamp(0, 200)));

  // Interpret the status code family:
  final family = res.statusCode ~/ 100;
  const meaning = {2: 'Success', 3: 'Redirect', 4: 'Client error', 5: 'Server error'};
  print('\nStatus family: ${meaning[family] ?? "Unknown"}');
}

// Typical output (abridged):
// --- Request ---
// GET  https://httpbin.org/get?hello=world
// Headers: User-Agent: dart-demo, Accept: application/json
//
// --- Response (231 ms) ---
// Status: 200 OK
// Headers:
//   content-type: application/json
//   date: Wed, 01 Jul 2026 10:00:00 GMT
//   ...
//
// --- Body (first 200 chars) ---
// { "args": { "hello": "world" }, ... }
//
// Status family: Success
